+        </p>
+      )}
+      <table className="sm-table">
+        <thead>
+          <tr>
+            {cols.map((c) => (
+              <th key={c.key} className={c.className}>
+                {c.label}
+              </th>
+            ))}
+          </tr>
+        </thead>
+        <tbody>
+          {rows.map((r, i) => (
+            <tr key={i}>
+              {cols.map((c) => (
+                <td key={c.key}>{r[c.key]}</td>
+              ))}
+            </tr>
+          ))}
+        </tbody>
+      </table>
+    </div>
+  );
+}
+
+// Section title helper — renders an H2 with data-anchor id for TOC jumps
+function SectionHeader({
+  id,
+  eyebrow,
+  title,
+}: {
+  id: string;
+  eyebrow?: string;
